import{_ as s,o as n,c as e,a2 as p}from"./chunks/framework.kxxRO88J.js";const u=JSON.parse('{"title":"프롬프트 작성법","description":"","frontmatter":{"sidebar_position":2},"headers":[],"relativePath":"03-codex-motion/prompt-basics.md","filePath":"03-codex-motion/prompt-basics.md"}'),t={name:"03-codex-motion/prompt-basics.md"};function i(l,a,o,d,c,r){return n(),e("div",null,[...a[0]||(a[0]=[p(`<h1 id="프롬프트-작성법" tabindex="-1">프롬프트 작성법 <a class="header-anchor" href="#프롬프트-작성법" aria-label="Permalink to &quot;프롬프트 작성법&quot;">​</a></h1><h2 id="효과적인-codex-프롬프트의-구조" tabindex="-1">효과적인 Codex 프롬프트의 구조 <a class="header-anchor" href="#효과적인-codex-프롬프트의-구조" aria-label="Permalink to &quot;효과적인 Codex 프롬프트의 구조&quot;">​</a></h2><p>Codex에게 Remotion 코드를 요청할 때, 모호한 요청은 모호한 코드를 낳습니다. 다음 네 가지 요소를 포함하면 원하는 결과를 훨씬 빠르게 얻을 수 있습니다.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[영상 사양] + [비주얼 씬 설명] + [스타일] + [오디오/텍스트 내용]</span></span></code></pre></div><hr><h2 id="나쁜-프롬프트-vs-좋은-프롬프트" tabindex="-1">나쁜 프롬프트 vs 좋은 프롬프트 <a class="header-anchor" href="#나쁜-프롬프트-vs-좋은-프롬프트" aria-label="Permalink to &quot;나쁜 프롬프트 vs 좋은 프롬프트&quot;">​</a></h2><h3 id="나쁜-프롬프트-예시" tabindex="-1">나쁜 프롬프트 예시 <a class="header-anchor" href="#나쁜-프롬프트-예시" aria-label="Permalink to &quot;나쁜 프롬프트 예시&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&quot;멋진 텍스트 애니메이션 만들어줘&quot;</span></span></code></pre></div><p>무엇이 문제인가:</p><ul><li>영상 크기가 없음 (1920×1080? 9:16?)</li><li>&quot;멋진&quot;이 무엇인지 정의되지 않음</li><li>텍스트 내용이 없음</li><li>애니메이션 방향과 타이밍이 없음</li></ul><p>Codex가 임의로 결정해야 하는 항목이 많아지면 원하는 결과가 나올 확률이 낮아집니다.</p><h3 id="좋은-프롬프트-예시" tabindex="-1">좋은 프롬프트 예시 <a class="header-anchor" href="#좋은-프롬프트-예시" aria-label="Permalink to &quot;좋은 프롬프트 예시&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1920x1080 영상을 만들어줘. 배경은 짙은 남색(#1a1a2e).</span></span>
<span class="line"><span>텍스트 &quot;TechFlow — 업무를 자동화하다&quot;가</span></span>
<span class="line"><span>프레임 0에서 아래 40px 위치에서 시작해</span></span>
<span class="line"><span>프레임 20까지 제자리로 올라오면서 페이드인.</span></span>
<span class="line"><span>폰트는 bold, 크기 72px, 색상 흰색.</span></span>
<span class="line"><span>총 길이 90프레임(30fps 기준 3초).</span></span></code></pre></div><p>좋은 이유:</p><ul><li>영상 사양 명시 (1920×1080, 30fps, 90프레임)</li><li>정확한 색상 코드 사용</li><li>애니메이션 시작 위치, 끝 위치, 타이밍 명시</li><li>텍스트 내용 포함</li></ul><hr><h2 id="프롬프트-구조-템플릿" tabindex="-1">프롬프트 구조 템플릿 <a class="header-anchor" href="#프롬프트-구조-템플릿" aria-label="Permalink to &quot;프롬프트 구조 템플릿&quot;">​</a></h2><p>다음 템플릿을 복사해 사용합니다.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[영상 사양]</span></span>
<span class="line"><span>크기: {너비}x{높이}</span></span>
<span class="line"><span>fps: {fps}</span></span>
<span class="line"><span>총 길이: {프레임 수}프레임 ({초}초)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>[비주얼 설명]</span></span>
<span class="line"><span>배경: {색상 또는 그라디언트}</span></span>
<span class="line"><span>요소 1: {설명, 위치, 크기}</span></span>
<span class="line"><span>요소 2: {설명, 위치, 크기}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>[애니메이션]</span></span>
<span class="line"><span>- {요소 1}: 프레임 {시작}~{끝} 동안 {동작}</span></span>
<span class="line"><span>- {요소 2}: 프레임 {시작}~{끝} 동안 {동작}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>[텍스트 내용]</span></span>
<span class="line"><span>{실제 텍스트}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>[반드시 지켜야 할 규칙]</span></span>
<span class="line"><span>- CSS @keyframes 사용 금지, Remotion의 interpolate() 사용</span></span>
<span class="line"><span>- extrapolateRight: &#39;clamp&#39; 항상 포함</span></span>
<span class="line"><span>- named export로 MyComposition 내보내기</span></span></code></pre></div><hr><h2 id="codex에게-반드시-상기시켜야-할-규칙" tabindex="-1">Codex에게 반드시 상기시켜야 할 규칙 <a class="header-anchor" href="#codex에게-반드시-상기시켜야-할-규칙" aria-label="Permalink to &quot;Codex에게 반드시 상기시켜야 할 규칙&quot;">​</a></h2><p>다음 규칙들은 스킬 모듈이 있어도 복잡한 프롬프트에서 Codex가 놓칠 수 있습니다. 중요한 요청에는 명시적으로 포함하는 것이 좋습니다.</p><table tabindex="0"><thead><tr><th>규칙</th><th>이유</th></tr></thead><tbody><tr><td><code>CSS @keyframes</code> 금지</td><td>Remotion 렌더러에서 동작하지 않음</td></tr><tr><td><code>interpolate()</code>에 <code>extrapolateRight: &#39;clamp&#39;</code></td><td>범위 초과 시 값 폭주 방지</td></tr><tr><td><code>useCurrentFrame()</code>으로만 프레임 접근</td><td>다른 방법은 렌더링 시 오작동</td></tr><tr><td><code>named export</code>로 컴포넌트 내보내기</td><td>Root.tsx에서 import하려면 필요</td></tr><tr><td><code>useVideoConfig()</code>에서 fps 가져오기</td><td>spring() 계산에 반드시 필요</td></tr></tbody></table><hr><h2 id="반복적-프롬프트-iterative-prompting" tabindex="-1">반복적 프롬프트 (Iterative Prompting) <a class="header-anchor" href="#반복적-프롬프트-iterative-prompting" aria-label="Permalink to &quot;반복적 프롬프트 (Iterative Prompting)&quot;">​</a></h2><p>한 번에 완벽한 결과를 기대하기보다, 여러 번의 대화로 점진적으로 개선하는 것이 효율적입니다.</p><p><strong>1단계: 기본 구조 생성</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1920x1080, 30fps, 90프레임 영상.</span></span>
<span class="line"><span>짙은 남색 배경에 흰 텍스트 &quot;TechFlow&quot;가 페이드인되는 컴포지션 만들어줘.</span></span></code></pre></div><p><strong>2단계: 세부 조정</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>텍스트 아래에 &#39;#0066CC&#39; 색상의 200px 너비 밑줄이</span></span>
<span class="line"><span>텍스트보다 10프레임 늦게 왼쪽에서 오른쪽으로 확장되도록 추가해줘.</span></span></code></pre></div><p><strong>3단계: 타이밍 조정</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>밑줄 애니메이션이 너무 빠르다. 20프레임 동안 천천히 나타나도록 조정해줘.</span></span></code></pre></div><p>각 단계에서 Studio로 결과를 확인하고, 다음 피드백을 줍니다. 이 방식이 한 번에 모든 것을 설명하려는 것보다 훨씬 안정적인 결과를 낳습니다.</p><hr><h2 id="실전-프롬프트-모음" tabindex="-1">실전 프롬프트 모음 <a class="header-anchor" href="#실전-프롬프트-모음" aria-label="Permalink to &quot;실전 프롬프트 모음&quot;">​</a></h2><p>다음 챕터들에서 구체적인 프롬프트 예시를 제공합니다. 지금은 구조와 원칙을 이해하는 것으로 충분합니다.</p><hr><p><a href="./text-animation.html">다음: 텍스트 애니메이션 →</a></p>`,38)])])}const b=s(t,[["render",i]]);export{u as __pageData,b as default};
